// Manual DI — fine for small projects
class UserRepo(private val api: UserApi, private val dao: UserDao)
class UserViewModel(private val repo: UserRepo) : ViewModel()

// Composition root in MyApp.onCreate
class MyApp : Application() {
  lateinit var container: AppContainer
  override fun onCreate() {
    super.onCreate()
    container = AppContainer(this)
  }
}

class AppContainer(context: Context) {
  val api: UserApi = buildRetrofit().create(UserApi::class.java)
  val db: AppDb = buildRoom(context)
  val userRepo: UserRepo = UserRepo(api, db.users())
  // Provide ViewModel factory for screens
}

// Service locator anti-pattern — avoid
class BadVM : ViewModel() {
  private val repo = UserRepo.getInstance()        // ❌ hidden coupling, hard to test
}

// Why explicit > implicit
// Explicit: replace UserRepo with FakeUserRepo in tests trivially.
// Implicit: have to mock the static getInstance(), brittle.

// Application
@HiltAndroidApp
class MyApp : Application()

// Module — provide bindings
@Module
@InstallIn(SingletonComponent::class)
object NetworkModule {
  @Provides @Singleton
  fun provideOkHttp(): OkHttpClient = OkHttpClient.Builder().build()

  @Provides @Singleton
  fun provideRetrofit(client: OkHttpClient): Retrofit =
    Retrofit.Builder().client(client).baseUrl("https://api/").build()

  @Provides @Singleton
  fun provideUserApi(retrofit: Retrofit): UserApi = retrofit.create(UserApi::class.java)
}

// Bind interface to impl — common case
@Module
@InstallIn(SingletonComponent::class)
abstract class RepoBindings {
  @Binds @Singleton
  abstract fun bindUserRepo(impl: UserRepoImpl): UserRepo
}

// ViewModel
@HiltViewModel
class HomeViewModel @Inject constructor(
  private val userRepo: UserRepo
