// Qualifier
@Qualifier @Retention(AnnotationRetention.BINARY)
annotation class AuthClient
@Qualifier @Retention(AnnotationRetention.BINARY)
annotation class IoDispatcher

@Module
@InstallIn(SingletonComponent::class)
object NetworkModule {
  @Provides @Singleton
  fun provideHttp(): OkHttpClient = OkHttpClient()

  @Provides @Singleton @AuthClient
  fun provideAuthHttp(tokens: TokenStore): OkHttpClient =
    OkHttpClient.Builder().addInterceptor(AuthInterceptor(tokens)).build()

  @Provides @IoDispatcher
  fun provideIo(): CoroutineDispatcher = Dispatchers.IO
}

class UserRepo @Inject constructor(
  @AuthClient private val authClient: OkHttpClient,
  @IoDispatcher private val io: CoroutineDispatcher
)

// Multibinding — Set<NavRouteContributor>
interface NavRouteContributor { fun routes(): List<Route> }

@Module
@InstallIn(SingletonComponent::class)
abstract class HomeFeatureModule {
  @Binds @IntoSet abstract fun bindHomeRoutes(impl: HomeRoutes): NavRouteContributor
}

@Module
@InstallIn(SingletonComponent::class)
abstract class CartFeatureModule {
  @Binds @IntoSet abstract fun bindCartRoutes(impl: CartRoutes): NavRouteContributor
}

class App @Inject constructor(
  private val contributors: Set<@JvmSuppressWildcards NavRouteContributor>
) {
  fun allRoutes(): List<Route> = contributors.flatMap { it.routes() }
}

// Production
@Module
@InstallIn(SingletonComponent::class)
object NetworkModule {
  @Provides @Singleton fun provideUserApi(): UserApi = realApi
}

// Test source set
@Module
@TestInstallIn(
  components = [SingletonComponent::class],
  replaces = [NetworkModule::class]
)
object FakeNetworkModule {
  @Provides @Singleton fun provideUserApi(): UserApi = FakeUserApi()
}

@HiltAndroidTest
class HomeScreenTest {
  @get:Rule(order = 0) val hiltRule = HiltAndroidRule(this)
  @get:Rule(order = 1) val composeRule = createAndroidComposeRule<HiltComponentActivity>()

  @Inject lateinit var repo: UserRepo

  @Before fun setUp() { hiltRule.inject() }

  @Test
  fun shows_user_name() {
    composeRule.setContent { HomeScreen() }
    composeRule.onNodeWithText("Alice").assertIsDisplayed()
  }
}

// Pure unit test alternative — no Hilt at all
@Test
fun `viewmodel emits success`() = runTest {
  val repo = FakeUserRepo(users = listOf(User(1, "Alice")))
  val vm = HomeViewModel(repo)
  advanceUntilIdle()
  assertEquals("Alice", vm.state.value.users.first().name)
}

